import React from "react";

const UserProfile = ({ user, handleLogout }) => {
  return (
    <div className="flex flex-col sm:flex-row items-center justify-between p-4 bg-white shadow-md rounded-lg mb-4 w-full">
      <div className="flex items-center space-x-3">
        <img
          src={user.photoURL || "/default-avatar.png"}
          alt="Avatar"
          className="w-12 h-12 rounded-full object-cover"
        />
        <div className="flex flex-col">
          <span className="font-semibold text-gray-800 text-sm sm:text-base truncate">
            {user.displayName || user.email}
          </span>
          <span className="text-gray-500 text-xs sm:text-sm">Sesión iniciada</span>
        </div>
      </div>

      <button
        onClick={handleLogout}
        className="mt-3 sm:mt-0 px-4 py-2 bg-red-500 text-white rounded-lg hover:bg-red-600 transition text-sm sm:text-base"
      >
        Cerrar sesión
      </button>
    </div>
  );
};

export default UserProfile;
